content = "#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

using namespace std;

double heapMedian(vector<int> lst) {
    if(lst.empty() || (lst.size() % 2 == 0))
        return NAN;

    nth_element(lst.begin(), lst.begin() + lst.size() / 2, lst.end());
    return lst[lst.size() / 2];
}

