    printMedian(heapMedian(vector<int>({7, 5, 3, 1, 9, 6, 4, 2, 8}))); // should print 5
    printMedian(heapMedian(vector<int>({}))); // should print None
    printMedian(heapMedian(vector<int>({1, 2, 3, 4, 5, 6, 7, 8}))); // should print None
    return 0;
