        Fire Color: <input type='color' id='fireColor'>
    </div>
    <div id='container'></div>

    <script>
        const NS = 'http://www.w3.org/2000/svg';
        const container = document.getElementById('container');

        // Time of day settings
        const timesOfDay = {
            dawn: { bg: ['#ff9a9e', '#fad0c4'], scale: '#8e44ad', fire: '#f1c40f' },
            day: { bg: ['#87CEEB', '#E0F7FA'], scale: '#2ecc71', fire: '#e67e22' },
            dusk: { bg: ['#4b6cb7', '#182848'], scale: '#c0392b', fire: '#f39c12' },
            night: { bg: ['#0f0c29', '#302b63', '#24243e'], scale: '#2c3e50', fire: '#e74c3c' }
        };

        function getTimeOfDay() {
            const hour = new Date().getHours();
            if (hour >= 5 && hour < 8) return 'dawn';
            if (hour >= 8 && hour < 17) return 'day';
            if (hour >= 17 && hour < 21) return 'dusk';
            return 'night';
        }

        function createGradient(id, colors) {
            const grad = document.createElementNS(NS, 'linearGradient');
            grad.setAttribute('id', id);
            colors.forEach((color, i) => {
                const stop = document.createElementNS(NS, 'stop');
                stop.setAttribute('offset', `${(i / (colors.length - 1)) * 100}%`);
                stop.setAttribute('stop-color', color);
                grad.appendChild(stop);
            });
            return grad;
        }

        function init() {
            const svg = document.createElementNS(NS, 'svg');
            svg.setAttribute('width', '100%');
            svg.setAttribute('height', '100%');
            svg.setAttribute('viewBox', '0 0 800 600');
            svg.setAttribute('preserveAspectRatio', 'xMidYMid meet');
            container.appendChild(svg);

