            body.setAttribute('rx', '100'); body.setAttribute('ry', '50');
            dragon.appendChild(body);

            const head = document.createElementNS(NS, 'circle');
            head.setAttribute('cx', '500'); head.setAttribute('cy', '280');
            head.setAttribute('r', '30');
            dragon.appendChild(head);

            svg.appendChild(dragon);

            // Fire
            const fire = document.createElementNS(NS, 'path');
            fire.setAttribute('d', 'M 530 280 Q 600 250 700 280 T 800 280');
            fire.setAttribute('stroke-width', '10');
            fire.setAttribute('stroke-linecap', 'round');
            fire.setAttribute('fill', 'none');
            fire.setAttribute('visibility', 'hidden');
            svg.appendChild(fire);

            // Logic for time of day
            const updateTheme = () => {
                const tod = getTimeOfDay();
                const theme = timesOfDay[tod];
                const bgGrad = createGradient('bgGrad', theme.bg);
                defs.innerHTML = ''; defs.appendChild(bgGrad);
                bgRect.setAttribute('fill', 'url(#bgGrad)');
                dragon.setAttribute('fill', theme.scale);
                fire.setAttribute('stroke', theme.fire);
            };
            updateTheme();

            // Animations
            let isFlying = false;
            let flyPos = 400;
            let fireOpacity = 0;

            function animate() {
                if (isFlying) {
                    flyPos += 5;
                    if (flyPos > 900) {
                        flyPos = -100;
                        isFlying = false;
                    }
                    dragon.setAttribute('transform', `translate(${flyPos - 400}, 0)`);
                }
                requestAnimationFrame(animate);
            }
            animate();

            dragon.addEventListener('mouseenter', () => {
                fire.setAttribute('visibility', 'visible');
            });
            dragon.addEventListener('mouseleave', () => {
                fire.setAttribute('visibility', 'hidden');
            });
            dragon.addEventListener('click', () => {
                isFlying = true;
            });

            document.getElementById('scaleColor').addEventListener('input', (e) => {
                dragon.setAttribute('fill', e.target.value);
            });
            document.getElementById('fireColor').addEventListener('input', (e) => {
                fire.setAttribute('stroke', e.target.value);
            });
        }
        window.onload = init;
    </script>
</body>
</html>
"""
