```go
package main

import (
	"fmt"
	"strings"
)

// mostFrequentDigit finds the digit that appears most frequently across all strings.
// In case of a tie, it returns the digit that appeared first in the concatenated string.
func mostFrequentDigit(numStrings []string) string {
	// Merge the slice of strings into one string.
	allDigits := strings.Join(numStrings, "")

	// Use a map to count occurrences of each digit.
	// Go maps do not preserve insertion order, so we use this for counting only.
	frequency := make(map[rune]int)
	for _, char := range allDigits {
		frequency[char]++
	}

	// To handle the 'first appearance' tie-breaker, we iterate through the original
	// concatenated string in order. The first digit encountered that has the
	// overall maximum frequency will be our result.
	maxCount := 0
	var maxDigit rune

	for _, char := range allDigits {
		count := frequency[char]
		if count > maxCount {
			maxCount = count
			maxDigit = char
		}
	}

	return string(maxDigit)
}

func main() {
	// Test the function
	fmt.Println(mostFrequentDigit([]string{"123", "234", "345"}))  // Returns: '1'
	fmt.Println(mostFrequentDigit([]string{"111", "222", "333"}))  // Returns: '1'
	fmt.Println(mostFrequentDigit([]string{"99999", "88888", "77777"}))  // Returns: '9'
}
```

Since Go does not have a built-in `OrderedDict` or `Counter` like Python, the logic is split into two passes: one to populate the frequency map and a second pass over the original string to identify the first digit that reaches the maximum count.")
</code>

