Thought: I need to implement a Fibonacci Heap class in Python. I'll start by writing the implementation to a file named `fib_heap.py`, including the Node class and the FibonacciHeap class with all the required operations: insert, union, find_min, extract_min, decrease_key, delete, and a way to display the heap.
<code>
content = "import math

class Node:
    def __init__(self, key):
        self.key = key
        self.degree = 0
        self.parent = None
        self.child = None
        self.left = self
        self.right = self
        self.mark = False

class FibonacciHeap:
    def __init__(self):
        self.min_node = None
        self.total_nodes = 0

    def insert(self, key):
        node = Node(key)
        if self.min_node is None:
            self.min_node = node
        else:
            self._add_to_root_list(node)
            if node.key < self.min_node.key:
                self.min_node = node
        self.total_nodes += 1
        return node

    def find_min(self):
        return self.min_node.key if self.min_node else None

    def union(self, other_heap):
        if not other_heap.min_node:
            return
        if not self.min_node:
            self.min_node = other_heap.min_node
            self.total_nodes = other_heap.total_nodes
            return

        # Merge root lists
        self._merge_lists(self.min_node, other_heap.min_node)
        if other_heap.min_node.key < self.min_node.key:
            self.min_node = other_heap.min_node
        self.total_nodes += other_heap.total_nodes

    def extract_min(self):
        z = self.min_node
        if z is not None:
            if z.child:
                children = self._get_nodes_in_list(z.child)
                for child in children:
                    self._add_to_root_list(child)
                    child.parent = None

            # Remove z from root list
            z.left.right = z.right
            z.right.left = z.left

            if z == z.right:
                self.min_node = None
            else:
                self.min_node = z.right
                self._consolidate()

            self.total_nodes -= 1
            return z.key
        return None

    def decrease_key(self, x, k):
        if k > x.key:
            return
        x.key = k
        y = x.parent
        if y is not None and x.key < y.key:
            self._cut(x, y)
            self._cascading_cut(y)
        if x.key < self.min_node.key:
            self.min_node = x

    def delete(self, x):
        self.decrease_key(x, float('-inf'))
        self.extract_min()

    def _consolidate(self):
        max_degree = int(math.log2(self.total_nodes)) + 2 if self.total_nodes > 0 else 2
        A = [None] * max_degree

        root_nodes = self._get_nodes_in_list(self.min_node)
        for w in root_nodes:
            x = w
            d = x.degree
            while A[d] is not None:
                y = A[d]
                if x.key > y.key:
                    x, y = y, x
                self._link(y, x)
                A[d] = None
                d += 1
            A[d] = x

        self.min_node = None
        for node in A:
            if node is not None:
                if self.min_node is None:
                    self.min_node = node
                    node.left = node.right = node
                else:
                    self._add_to_root_list(node)
                    if node.key < self.min_node.key:
                        self.min_node = node

    def _link(self, y, x):
        # Remove y from root list
        y.left.right = y.right
        y.right.left = y.left
        # Make y a child of x
        y.parent = x
        if x.child is None:
            x.child = y
            y.left = y.right = y
        else:
            self._add_to_list(x.child, y)
        x.degree += 1
        y.mark = False

    def _cut(self, x, y):
        # Remove x from child list of y
        if x.right == x:
            y.child = None
        else:
            x.left.right = x.right
            x.right.left = x.left
            if y.child == x:
                y.child = x.right
        y.degree -= 1
        self._add_to_root_list(x)
        x.parent = None
        x.mark = False

    def _cascading_cut(self, y):
        z = y.parent
        if z is not None:
            if not y.mark:
                y.mark = True
            else:
                self._cut(y, z)
                self._cascading_cut(z)

    def _add_to_root_list(self, node):
        self._add_to_list(self.min_node, node)

    def _add_to_list(self, head, node):
        node.left = head
        node.right = head.right
        head.right.left = node
        head.right = node

    def _merge_lists(self, h1, h2):
        h1_next = h1.right
        h2_prev = h2.left
        h1.right = h2
        h2.left = h1
        h1_next.left = h2_prev
        h2_prev.right = h1_next

    def _get_nodes_in_list(self, head):
        nodes = []
        if head is None: return nodes
        curr = head
        while True:
            nodes.append(curr)
            curr = curr.right
            if curr == head: break
        return nodes

    def __str__(self):
        if not self.min_node: return "Empty Heap"
        roots = self._get_nodes_in_list(self.min_node)
        return "Root List: " + " -> ".join(str(n.key) for n in roots)
"
