            // Reset styles and error message
            rootInput.style.border = "";
            numberInput.style.border = "";
            errorEl.innerText = '';

            // 4. Validate that inputs are numbers before checking correctness
            if (numberVal === '' || rootVal === '' || isNaN(numberVal) || isNaN(rootVal)) {
                rootInput.style.border = "2px solid red";
                numberInput.style.border = "2px solid red";
                // 5. Error message appears in the form, not as an alert
                errorEl.innerText = 'Error: Both fields must contain valid numbers';
                return;
