                rootInput.style.border = "2px solid red";
                numberInput.style.border = "2px solid red";
                // 5. Error message appears in the form, not as an alert
                errorEl.innerText = 'Error: Both fields must contain valid numbers';
                return;
            }

            var num = parseFloat(numberVal);
            var root = parseFloat(rootVal);

            // 2 & 3. Correctly calculate and check if the root is the square root
            if (Math.pow(root, 2) !== num) {
                rootInput.style.border = "2px solid red";
                errorEl.innerText = 'Error: Incorrect root';
            } else {
                rootInput.style.border = "2px solid green";
                errorEl.style.color = 'green';
                errorEl.innerText = 'Correct!';
                // Reset color for next attempt
                setTimeout(() => { errorEl.style.color = 'red'; }, 3000);
            }
