```python
import math
import sympy

def is_perfect_square(n):
    if n < 0: return False
    sr = math.isqrt(n)
    return sr*sr == n

def count_special_numbers(n_digits):
    start = 10**(n_digits - 1)
    end = 10**n_digits
    count = 0
    for i in range(start, end):
        s_i = str(i)
        if s_i[0] == '1' or s_i[-1] == '1':
            if len(sympy.primefactors(i)) >= 3:
                count += 1
