    // Make sure, planet1Index is the smaller index
    if planet1Index > planet2Index {
        planet1Index, planet2Index = planet2Index, planet1Index
    }

    // Return all the planets located between planet1 and planet2
    return planetsInOrder[planet1Index+1 : planet2Index]
