        table, th, td { border: 1px solid black; padding: 10px; text-align: center; }
        th { background-color: #f2f2f2; cursor: pointer; position: relative; }
        .del-col-btn { margin-left: 10px; cursor: pointer; color: red; }
        .del-row-btn { cursor: pointer; color: red; }
        .editable { cursor: pointer; background-color: #fffdf0; }
        .pagination-ctrl { margin-top: 10px; }
    </style>
</head>
<body>
    <div id="tableContainer"></div>
    <div class="pagination-ctrl">
        <button id="prev">Prev</button>
        <button id="next">Next</button>
    </div>

    <script>
        class DynamicTable {
            constructor(data, containerID) {
                this.data = data; // 2D Array
                this.container = document.getElementById(containerID);
                this.page = 0;
                this.pageSize = 3;
                this.sortCol = null;
                this.sortDirection = 1;
                this.init();
            }

            init() {
                this.render();
            }

            render() {
                this.container.innerHTML = '';
                const table = document.createElement('table');

                // Pagination slicing for rows
                const startRow = this.page * this.pageSize;
                const endRow = startRow + this.pageSize;
                const pageData = this.data.slice(startRow, endRow);

                if (pageData.length === 0) {
                    this.container.innerText = 'No more data';
                    return;
                }

                // Header Row
                const headerRow = document.createElement('tr');
                const colCount = this.data[0].length;
                for (let j = 0; j < colCount; j++) {
                    const th = document.createElement('th');
                    th.innerHTML = `Col ${j} <span class="del-col-btn" data-col="${j}"> [X]</span>`;
                    th.onclick = (e) => {
                        if (e.target.className !== 'del-col-btn') this.sort(j);
                    };
                    th.querySelector('.del-col-btn').onclick = (e) => {
                        e.stopPropagation();
                        this.deleteColumn(j);
                    };
                    headerRow.appendChild(th);
                }
                table.appendChild(headerRow);

                // Data Rows
                pageData.forEach((rowData, rowIndex) => {
                    const actualRowIndex = startRow + rowIndex;
                    const tr = document.createElement('tr');

                    rowData.forEach((cellData, colIndex) => {
                        const td = document.createElement('td');
                        td.innerText = cellData;
                        td.id = `cell-${actualRowIndex}-${colIndex}`;
                        td.className = 'editable';
                        td.contentEditable = true;
                        td.onblur = (e) => {
                            this.data[actualRowIndex][colIndex] = e.target.innerText;
                        };
                        tr.appendChild(td);
                    });

                    // Delete Row Button
                    const actionTd = document.createElement('td');
                    const delBtn = document.createElement('button');
                    delBtn.innerText = 'Delete Row';
                    delBtn.className = 'del-row-btn';
                    delBtn.onclick = () => this.deleteRow(actualRowIndex);
                    actionTd.appendChild(delBtn);
                    tr.appendChild(actionTd);

                    table.appendChild(tr);
                });

                this.container.appendChild(table);
            }

            sort(colIndex) {
                if (this.sortCol === colIndex) {
                    this.sortDirection *= -1;
                } else {
                    this.sortCol = colIndex;
                    this.sortDirection = 1;
                }

                this.data.sort((a, b) => {
                    const valA = a[colIndex];
                    const valB = b[colIndex];
                    return valA < valB ? -this.sortDirection : (valA > valB ? this.sortDirection : 0);
                });
                this.render();
            }

            deleteRow(index) {
                this.data.splice(index, 1);
                this.render();
            }

            deleteColumn(index) {
                this.data.forEach(row => row.splice(index, 1));
                this.sortCol = null;
                this.render();
            }

            nextPage() {
                if ((this.page + 1) * this.pageSize < this.data.length) {
                    this.page++;
                    this.render();
                }
            }

            prevPage() {
                if (this.page > 0) {
                    this.page--;
                    this.render();
                }
            }
        }

        // Initial Data: 10 rows, 3 cols to demonstrate pagination
        const initialData = Array.from({ length: 10 }, (_, i) => 
            [`Row ${i+1} Col 0`, `Row ${i+1} Col 1`, `Row ${i+1} Col 2`]
        );

        const myTable = new DynamicTable(initialData, 'tableContainer');
        document.getElementById('next').onclick = () => myTable.nextPage();
        document.getElementById('prev').onclick = () => myTable.prevPage();
    </script>
</body>
</html>
"""
