from botocore.exceptions import ClientError

class RDSConnectionManager:
    def __init__(self, secret_name, region_name='us-west-2'):
        self.secret_name = secret_name
        self.region_name = region_name
        self._connection = None

    def _get_secret(self):
        session = boto3.session.Session()
        client = session.client(service_name='secretsmanager', region_name=self.region_name)
        try:
            response = client.get_secret_value(SecretId=self.secret_name)
            return json.loads(response['SecretString'])
        except ClientError as e:
            raise Exception(f"Could not retrieve secret: {e}")

    def get_connection(self):
        if self._connection is None or self._connection.closed:
            creds = self._get_secret()
            conn_str = (
                f"DRIVER={{ODBC Driver 17 for SQL Server}};"
                f"SERVER={creds['host']};"
                f"DATABASE={creds['dbname']};"
                f"UID={creds['username']};"
                f"PWD={creds['password']}"
            )
            self._connection = pyodbc.connect(conn_str)
        return self._connection

    def execute_query(self, query, params=None):
        conn = self.get_connection()
        cursor = conn.cursor()
        try:
            if params:
                cursor.execute(query, params)
            else:
                cursor.execute(query)
            if query.strip().upper().startswith('SELECT'):
                return cursor.fetchall()
            conn.commit()
            return True
        finally:
            cursor.close()

    def close(self):
        if self._connection:
            self._connection.close()
