class Solution {
    private final List<String> planets = Arrays.asList("Mercury", "Venus", "Earth", "Mars", "Jupiter", "Saturn", "Uranus", "Neptune");

    public List<String> planetsBetween(String planet1, String planet2) {
        int index1 = planets.indexOf(planet1);
        int index2 = planets.indexOf(planet2);

        if (index1 == -1 || index2 == -1) {
            throw new IllegalArgumentException("One or both of the provided planets are incorrect");
        }

        int start = Math.min(index1, index2);
        int end = Math.max(index1, index2);

        // subList(fromIndex, toIndex) is inclusive of fromIndex and exclusive of toIndex
        // We want planets BETWEEN, so we start at start + 1 and end at end
        return new ArrayList<>(planets.subList(start + 1, end));
    }

    public static void main(String[] args) {
        Solution sol = new Solution();
        System.out.println(sol.planetsBetween("Jupiter", "Neptune")); // [Saturn, Uranus]
        System.out.println(sol.planetsBetween("Earth", "Mercury"));   // [Venus]
        System.out.println(sol.planetsBetween("Mercury", "Uranus"));  // [Venus, Earth, Mars, Jupiter, Saturn]
    }
}"
