content = """const { \n  GraphQLObjectType, \n  GraphQLString, \n  GraphQLInt, \n  GraphQLID, \n  GraphQLList, \n  GraphQLNonNull 
} = require('graphql');
const { BookType, UserType, BorrowType } = require('./types');

// Mock Database
const books = [];
const users = [];
const logs = [];

const RootQuery = new GraphQLObjectType({
  name: 'RootQueryType',
  fields: {
    book: {
      type: BookType,
      args: { id: { type: GraphQLID } },
      resolve: (parent, args) => books.find(b => b.id === args.id)
    },
    books: {
      type: new GraphQLList(BookType),
      args: {
        title: { type: GraphQLString },
        author: { type: GraphQLString },
        year: { type: GraphQLInt }
      },
      resolve: (parent, args) => {
        return books.filter(b => 
          (!args.title || b.title.includes(args.title)) &&
          (!args.author || b.author === args.author) &&
          (!args.year || b.yearOfPublication === args.year)
        );
      }
    },
    user: {
      type: UserType,
      args: { id: { type: GraphQLID } },
      resolve: (parent, args) => users.find(u => u.id === args.id)
    }
  }
});

const RootMutation = new GraphQLObjectType({
  name: 'RootMutationType',
  fields: {
    updateBook: {
      type: BookType,
      args: {
        id: { type: GraphQLNonNull(GraphQLID) },
        title: { type: GraphQLString },
        isAvailable: { type: GraphQLString }
      },
      resolve: (parent, args) => {
        const book = books.find(b => b.id === args.id);
        if (!book) throw new Error('Book not found');
        if (args.title) book.title = args.title;
        if (args.isAvailable) book.isAvailable = args.isAvailable;
        return book;
      }
    },
    checkoutBook: {
      type: BorrowType,
      args: {
        userId: { type: GraphQLNonNull(GraphQLID) },
        bookId: { type: GraphQLNonNull(GraphQLID) }
      },
      resolve: (parent, args) => {
        const book = books.find(b => b.id === args.bookId);
        const user = users.find(u => u.id === args.userId);
        if (!book || !user) throw new Error('User or Book not found');
        if (book.isAvailable === 'false') throw new Error('Book already checked out');

        book.isAvailable = 'false';
        const log = { id: logs.length + 1, user, book, borrowDate: new Date() };
        logs.push(log);
        return log;
      }
    }
  }
});

module.exports = { RootQuery, RootMutation };
