final_answer("```python
def invert_case(char):
    if char.isupper():
        return char.lower()
    elif char.islower():
        return char.upper()
    return char

def replace_and_shift(char, shift):
    if not char.isalpha():
        return char
    is_upper = char.isupper()
    char_lower = char.lower()

    # Both vowels and consonants are shifted forward by 'shift' in the alphabet
    shifted = chr((ord(char_lower) - ord('a') + shift) % 26 + ord('a'))

    return shifted.upper() if is_upper else shifted.lower()

def deshift(char, shift):
    if not char.isalpha():
        return char
    is_upper = char.isupper()
    char_lower = char.lower()

    # Shift back by 'shift'
    unshifted = chr((ord(char_lower) - ord('a') - shift) % 26 + ord('a'))

    return unshifted.upper() if is_upper else unshifted.lower()

def decode_error(cipher_text, shift=4):
    # 1. Invert the case of all English alphabets
    text = "".join(invert_case(c) for c in cipher_text)

    # 2 & 3. Replace alphabets (vowels and consonants) with characters 'shift' places after
    text = "".join(replace_and_shift(c, shift) for c in text)

    # 4. De-shift the position of each character
    text = "".join(deshift(c, shift) for c in text)

    return text
```")
