js_content = "async function getChessClubOutcomes() {
    try {
        const response = await fetch('https://example.com/api/chessoutcomes');
        if (!response.ok) {
            throw new Error(`Server Error: ${response.status}`);
        }
        const data = await response.json();
        return data;
    } catch (error) {
        console.error('Fetch Error: ', error);
        throw error;
    }
}

function sortTable(column, order) {
    const table = document.querySelector('#chess-table');
    const tbody = table.tBodies[0];
    const rows = Array.from(tbody.rows);

    rows.sort((rowA, rowB) => {
        const cellA = rowA.cells[column].textContent;
        const cellB = rowB.cells[column].textContent;
        const valA = isNaN(cellA) ? cellA : parseFloat(cellA);
        const valB = isNaN(cellB) ? cellB : parseFloat(cellB);

        if (order === 'asc') return valA > valB ? 1 : -1;
        return valA < valB ? 1 : -1;
    });

    rows.forEach(row => tbody.appendChild(row));
}

async function init() {
    const errorDiv = document.getElementById('error-message');
    const tbody = document.querySelector('#chess-table tbody');
    try {
        const data = await getChessClubOutcomes();
        data.forEach(item => {
            const row = tbody.insertRow();
            row.insertCell().textContent = item.club;
            row.insertCell().textContent = item.wins;
            row.insertCell().textContent = item.losses;
            row.insertCell().textContent = item.draws;
        });
    } catch (err) {
        errorDiv.textContent = 'Failed to load chess data: ' + err.message;
