content = "const Firestore = require('@google-cloud/firestore');
const express = require('express');
const app = express();

const db = new Firestore();
const choreRef = db.collection('chores');

// Real-time synchronization listener
choreRef.onSnapshot(snapshot => {
  snapshot.docChanges().forEach(change => {
    if (change.type === 'added') {
      console.log('New chore incorporated: ', change.doc.data());
    }
    if (change.type === 'modified') {
      console.log('Chore modified: ', change.doc.data());
    }
    if (change.type === 'removed') {
      console.log('Chore obliterated: ', change.doc.data());
    }
  });
});

app.use(express.json());

// Endpoint to incorporate a chore
app.post('/chores', async (req, res) => {
  try {
    const { chore, phase } = req.body;
    const docRef = await choreRef.add({
      chore,
      phase: phase || 'Not yet started',
      timestamp: Firestore.FieldValue.serverTimestamp()
    });
    res.status(201).send({ id: docRef.id });
  } catch (e) {
    res.status(500).send(e.message);
  }
});

// Endpoint to modify a chore
app.put('/chores/:id', async (req, res) => {
  try {
    const { phase, status } = req.body;
    await choreRef.doc(req.params.id).update({
      phase: phase,
      status: status,
      lastModified: Firestore.FieldValue.serverTimestamp()
    });
    res.sendStatus(200);
  } catch (e) {
    res.status(500).send(e.message);
  }
});

// Endpoint to obliterate a chore
app.delete('/chores/:id', async (req, res) => {
  try {
    await choreRef.doc(req.params.id).delete();
    res.sendStatus(200);
  } catch (e) {
    res.status(500).send(e.message);
  }
});

app.listen(3000, () => console.log('Chore Coordination Framework active on port 3000'));
"
