Thought: I will implement a tic-tac-toe game with an AI opponent using the Minimax algorithm. I'll write this into a file named `tictactoe_ai.py`.
<code>
content = "import math
import random

BOARD_SIZE = 3
PLAYER = 'X'
AI = 'O'

def print_board(board):
    for row in board:
        print(' | '.join(row))
        print('-' * 9)

def is_winner(board, player):
    # Check rows
    for row in board:
        if all(s == player for s in row): return True
    # Check cols
    for col in range(BOARD_SIZE):
        if all(board[row][col] == player for row in range(BOARD_SIZE)): return True
    # Check diagonals
    if all(board[i][i] == player for i in range(BOARD_SIZE)): return True
    if all(board[i][BOARD_SIZE - 1 - i] == player for i in range(BOARD_SIZE)): return True
    return False

def is_board_full(board):
    return all(cell != ' ' for row in board for cell in row)

def minimax(board, depth, is_maximizing):
    if is_winner(board, AI): return 10 - depth
    if is_winner(board, PLAYER): return depth - 10
    if is_board_full(board): return 0

    if is_maximizing:
        best_score = -math.inf
        for r in range(BOARD_SIZE):
            for c in range(BOARD_SIZE):
                if board[r][c] == ' ':
                    board[r][c] = AI
                    score = minimax(board, depth + 1, False)
                    board[r][c] = ' '
                    best_score = max(score, best_score)
        return best_score
    else:
        best_score = math.inf
        for r in range(BOARD_SIZE):
            for c in range(BOARD_SIZE):
                if board[r][c] == ' ':
                    board[r][c] = PLAYER
                    score = minimax(board, depth + 1, True)
                    board[r][c] = ' '
                    best_score = min(score, best_score)
        return best_score

def best_move(board):
    best_score = -math.inf
    move = None
    for r in range(BOARD_SIZE):
        for c in range(BOARD_SIZE):
            if board[r][c] == ' ':
                board[r][c] = AI
                score = minimax(board, 0, False)
                board[r][c] = ' '
                if score > best_score:
                    best_score = score
                    move = (r, c)
    return move

def main():
    board = [[' ' for _ in range(BOARD_SIZE)] for _ in range(BOARD_SIZE)]
    print("Tic-Tac-Toe AI (You are X, AI is O)")

    while True:
        print_board(board)
        # Player move
        try:
            move = input("Enter move (row,col) e.g. 0,0: ").split(',')
            r, c = int(move[0]), int(move[1])
            if board[r][c] != ' ':
                print("Cell occupied!")
                continue
        except (ValueError, IndexError):
            print("Invalid input!")
            continue

        board[r][c] = PLAYER
        if is_winner(board, PLAYER): 
            print_board(board)
            print("You win!"); break
        if is_board_full(board): 
            print_board(board)
            print("Draw!"); break

        # AI move
        print("AI is thinking...")
        ai_move = best_move(board)
        if ai_move:
            board[ai_move[0]][ai_move[1]] = AI

        if is_winner(board, AI): 
            print_board(board)
            print("AI wins!"); break
        if is_board_full(board): 
            print_board(board)
            print("Draw!"); break

if __name__ == '__main__':
    main()
"
