js_content = """document.addEventListener('DOMContentLoaded', () => {
    const grid = document.getElementById('grid');
    const color1Input = document.getElementById('color1');
    const color2Input = document.getElementById('color2');

    // Create 3x3 grid (9 cells)
    for (let i = 0; i < 9; i++) {
        const cell = document.createElement('div');
        cell.className = 'grid-cell';

        // Set initial color
        cell.style.backgroundColor = color1Input.value;

        // Hover event
        cell.addEventListener('mouseenter', () => {
            cell.style.backgroundColor = color2Input.value;
        });

        // Mouse leave event
        cell.addEventListener('mouseleave', () => {
            cell.style.backgroundColor = color1Input.value;
        });

        // Touch event for mobile
        cell.addEventListener('touchstart', (e) => {
            e.preventDefault();
            cell.style.backgroundColor = color2Input.value;
        });
        cell.addEventListener('touchend', () => {
            cell.style.backgroundColor = color1Input.value;
        });

        grid.appendChild(cell);
    }

    // Update all cells when color inputs change
    const updateColors = () => {
        const cells = document.querySelectorAll('.grid-cell');
        cells.forEach(cell => {
            cell.style.backgroundColor = color1Input.value;
        });
    };

    color1Input.addEventListener('input', updateColors);
    color2Input.addEventListener('input', () => {
        // We don't need to update current cells because hover uses the current value of color2Input
        // but for feedback we can just log it or update a status
    });
});"""
