content = "import java.util.*;
import java.util.stream.*;

// Strategy Pattern for Performance Grading
interface Performance {
    int grade();
}

class ConcertoPerformance implements Performance {
    private int grading;
    public ConcertoPerformance() {
        this.grading = new Random().nextInt(100) + 1;
    }
    @Override
    public int grade() {
        return grading;
    }
}

// Base Abstract Class
public abstract class MusicStudent {
    private String name;
    protected Performance performance;

    public MusicStudent(String name) {
        this.name = name;
    }

    public String getName() {
        return name;
    }

    public abstract MusicStudent getMentor();
    public abstract String getSpecialization();
    public int getGrade() {
        return performance.grade();
    }
}

// Instrumental Specialization
class InstrumentalStudent extends MusicStudent {
    private String instrument;
    private MusicStudent mentor;

    public InstrumentalStudent(String name, String instrument, MusicStudent mentor) {
        super(name);
        this.instrument = instrument;
        this.mentor = mentor;
        this.performance = new ConcertoPerformance();
    }

    @Override
    public MusicStudent getMentor() {
        return mentor;
    }

    @Override
    public String getSpecialization() {
        return "Instrumental: " + instrument;
    }

    public String getInstrument() {
        return instrument;
    }
}

// Vocal Specialization
class VocalStudent extends MusicStudent {
    private String voiceType;
    private MusicStudent mentor;

    public VocalStudent(String name, String voiceType, MusicStudent mentor) {
        super(name);
        this.voiceType = voiceType;
        this.mentor = mentor;
        this.performance = new ConcertoPerformance();
    }

    @Override
    public MusicStudent getMentor() {
        return mentor;
    }

    @Override
    public String getSpecialization() {
        return "Vocal: " + voiceType;
    }
}

// Student Manager for Stream API operations
class StudentRegistry {
    private List<MusicStudent> students = new ArrayList<>();

    public void addStudent(MusicStudent s) { students.add(s); }

    public List<MusicStudent> sortByGrade() {
        return students.stream()
            .sorted(Comparator.comparingInt(MusicStudent::getGrade).reversed())
            .collect(Collectors.toList());
    }

    public Optional<MusicStudent> findHighestGrade() {
        return students.stream()
            .max(Comparator.comparingInt(MusicStudent::getGrade));
    }

    public List<MusicStudent> filterByInstrument(String instrument) {
        return students.stream()
            .filter(s -> s instanceof InstrumentalStudent && ((InstrumentalStudent) s).getInstrument().equalsIgnoreCase(instrument))
            .collect(Collectors.toList());
    }
}
