<code>
content = "import java.time.LocalDate;
import java.time.DayOfWeek;
import java.time.ZoneId;
import java.time.DateTimeException;
import java.util.stream.Stream;
import java.util.Map;
import java.util.HashMap;
import java.util.function.Function;
import java.util.stream.Collectors;

public class DayOfWeekCalculator {
    public static void main(String[] args) {
        try {
            // Test single date
            int day = 15, month = 6, year = 2021;
            DayOfWeek dow = getDayOfWeek(day, month, year);
            System.out.println("Date " + day + "/" + month + "/" + year + " falls on: " + dow);

            // Test range
            int sDay = 1, sMonth = 1, sYear = 2021;
            int eDay = 31, eMonth = 12, eYear = 2021;
            Map<DayOfWeek, Long> counts = getDayOfWeekCountList(sDay, sMonth, sYear, eDay, eMonth, eYear);
            System.out.println("Day counts from " + sDay + "/" + sMonth + "/" + sYear + " to " + eDay + "/" + eMonth + "/" + eYear + ": " + counts);

            // Test invalid date (Feb 30)
            System.out.println("Testing invalid date (Feb 30, 2021)...");
            getDayOfWeek(30, 2, 2021);
        } catch (DateTimeException e) {
            System.out.println("Invalid date provided: " + e.getMessage());
        }
    }

    public static DayOfWeek getDayOfWeek(int dayOfMonth, int month, int year) {
        // LocalDate.of throws DateTimeException for invalid dates (e.g., Feb 30)
        // It inherently handles leap years and system default time zone context
        LocalDate date = LocalDate.of(year, month, dayOfMonth);
        return date.getDayOfWeek();
    }

    public static Map<DayOfWeek, Long> getDayOfWeekCountList(int startDay, int startMonth, int startYear, int endDay, int endMonth, int endYear) {
        LocalDate startDate = LocalDate.of(startYear, startMonth, startDay);
        LocalDate endDate = LocalDate.of(endYear, endMonth, endDay);

        long daysBetween = java.time.temporal.ChronoUnit.DAYS.between(startDate, endDate) + 1;

        return Stream.iterate(startDate, date -> date.plusDays(1))
              .limit(daysBetween)
              .map(LocalDate::getDayOfWeek)
              .collect(Collectors.groupingBy(Function.identity(), Collectors.counting()));
    }
}" 
