    bool public isTestatorAlive = true;

    struct Beneficiary {
        address beneficiaryAddress;
        uint percentage;
    }

    Beneficiary[] public beneficiaries;
    mapping(address => uint) public inheritance;

    event LogInheritance(address beneficiary, uint amount);
    event StatusChanged(bool alive);

    constructor(address _oracle) public {
        testator = msg.sender;
        oracle = _oracle;
    }

    function addBeneficiary(address _beneficiary, uint _percentage) public {
        require(msg.sender == testator, "Only the testator can add beneficiaries");
        require(isTestatorAlive, "The testator is no longer alive :(");

        beneficiaries.push(Beneficiary({
            beneficiaryAddress: _beneficiary,
            percentage: _percentage
        }));
    }

    function confirmDeath() public {
        require(msg.sender == oracle, "Only the oracle can confirm status");
        isTestatorAlive = false;
        emit StatusChanged(false);
        executeEstate();
    }

    function executeEstate() internal {
        uint totalBalance = address(this).balance;
        for (uint i = 0; i < beneficiaries.length; i++) {
            address bAddr = beneficiaries[i].beneficiaryAddress;
            uint amount = (totalBalance * beneficiaries[i].percentage) / 100;
            inheritance[bAddr] += amount;
            payable(bAddr).transfer(amount);
            emit LogInheritance(bAddr, amount);
        }
    }

    receive() external payable {}
}

